CREATE TABLE ItemSize (
ItemSize decimal(4,2) NOT NULL primary key
);

CREATE TABLE Customer (
CustomerID decimal(6,0) NOT NULL primary key,
FirstName varchar(30),
LastName varchar(30),
StreetAddress varchar(50),
City varchar(50),
State varchar(10),
PostalCode varchar(6),
Country varchar(30),
Phone varchar(14)
);

CREATE TABLE Employee (
EmployeeID decimal(6,0) NOT NULL primary key,
FirstName varchar(30),
LastName varchar(30),
Address varchar(50),
City varchar(50),
State varchar(10),
ZIP varchar(6),
Phone varchar(14),
HireDate date,
ManagerID decimal(6,0),
SSN varchar(11),
EmailAddress varchar(100)
);


CREATE TABLE Manufacturer (
ManufacturerID decimal(6,0) NOT NULL primary key,
ManufacturerName varchar(255),
Address1 varchar(255),
Address2 varchar(255),
City varchar(100),
State varchar(50),
PostalCode varchar(25),
Phone varchar(20),
Fax varchar(20),
Contact varchar(255),
URL varchar(255)
);


CREATE TABLE Product (
ProductID decimal(6,0) NOT NULL primary key,
ProductName varchar(255),
ManufacturerID int,
Composition varchar(255),
ListPrice decimal(6,2),
Gender varchar(255),
Category varchar(255),
Color varchar(255),
Description varchar(2000)
);

CREATE TABLE InventoryItem (
ProductID decimal(6,0) NOT NULL references product,
ItemSize decimal(4,2) NOT NULL references itemSize,
QtyOnHand decimal(4,0),
constraint Inventory_Item_pk primary key (ProductID, ItemSize)
);



CREATE TABLE Purchase (
PurchaseID decimal(6,0) NOT NULL primary key,
PurchaseDate DATE,
employeeID decimal(6,0) references employee,
ExpectedDeliveryDate DATE,
ManufacturerID decimal(6,0) references manufacturer,
Shipping decimal(5,2)
);

CREATE TABLE PurchaseItem (
ProductID decimal(6,0) NOT NULL,
ItemSize decimal(4,2) NOT NULL,
PurchaseID decimal(6,0) NOT NULL references purchase,
Quantity decimal(6,2),
PurchasePrice decimal(6,2),
constraint PurchaseItem_pk primary key (ProductID, ItemSize, PurchaseID)
,constraint purchaseitem_inventoryitem_fk foreign key (ItemSize, ProductID) references inventoryItem(ItemSize, ProductID)
);

CREATE TABLE Sale (
SaleID decimal(6,0) NOT NULL primary key,
SaleDate DATE,
CustomerID decimal(6,0) references customer,
Tax decimal(5,2),
Shipping decimal(5,2)
);


CREATE TABLE SaleItem (
SaleID decimal(6,0) NOT NULL references sale,
ProductID decimal(6,0) NOT NULL,
ItemSize decimal(4,2) NOT NULL,
Quantity decimal(4,0),
SalePrice decimal(5,0),
constraint SaleItem_pk primary key (SaleID, ItemSize, ProductID)
,constraint saleitem_inventoryitem_fk foreign key (ItemSize, ProductID) references inventoryItem(ItemSize, ProductID)
);

CREATE TABLE WageEmployee (
EmployeeID int NOT NULL primary key references employee,
Wage decimal(5,2),
MaxHours decimal(5,2)
);

CREATE TABLE SalaryEmployee (
EmployeeID int NOT NULL primary key references employee,
Salary decimal(6,0)
);
















